sub cocktail_shaker_sort {
  my @a = @_;
  my $start = 0;
  my $end = $#a;
  my $swapped = 1;
  while ($swapped) {
    $swapped = 0;
    for my $i ($start .. $end - 1) { if ($a[$i] > $a[$i + 1]) { @a[$i, $i + 1] = @a[$i + 1, $i]; $swapped = 1; } }
    last unless $swapped;
    $swapped = 0;
    $end--;
    for (my $i = $end; $i > $start; $i--) { if ($a[$i - 1] > $a[$i]) { @a[$i - 1, $i] = @a[$i, $i - 1]; $swapped = 1; } }
    $start++;
  }
  return @a;
}
